const h=$input.item.json.headers||{};
const body=$input.item.json.body||{};
const token=h['x-meta-token'];
const account=h['x-meta-account'];
const action=(body.action||'').toLowerCase();
if(!token||!account)return[{json:{success:false,error:'Missing Meta credentials'}}];
const GRAPH='https://graph.facebook.com/v19.0';
let result;

if(action==='toggle'){
  const campaignId=body.campaign_id;
  const status=body.status;
  if(!campaignId)return[{json:{success:false,error:'Missing campaign_id'}}];
  if(!['ACTIVE','PAUSED'].includes(status))return[{json:{success:false,error:'status must be ACTIVE or PAUSED'}}];
  const r=await fetch(`${GRAPH}/${campaignId}?access_token=${token}`,{
    method:'POST',
    headers:{'Content-Type':'application/x-www-form-urlencoded'},
    body:new URLSearchParams({status}).toString()
  });
  const d=await r.json();
  result=d.error?{success:false,error:d.error.message}:{ok:true,campaign_id:campaignId,status};

}else if(action==='create_campaign'){
  const name=(body.name||'').trim();
  if(!name)return[{json:{success:false,error:'Campaign name is required'}}];
  const VALID=['OUTCOME_SALES','OUTCOME_TRAFFIC','OUTCOME_LEADS','OUTCOME_AWARENESS','OUTCOME_ENGAGEMENT','OUTCOME_APP_PROMOTION'];
  const objective=VALID.includes(body.objective)?body.objective:'OUTCOME_SALES';
  const daily_budget=Math.max(100,parseInt(body.daily_budget)||1000);
  const countries=Array.isArray(body.countries)&&body.countries.length?body.countries:['US'];
  const start_time=body.start_time||new Date().toISOString();
  const cRes=await fetch(`${GRAPH}/act_${account}/campaigns`,{
    method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},
    body:new URLSearchParams({name,objective,status:'PAUSED',special_ad_categories:'[]',access_token:token}).toString()
  });
  const campaign=await cRes.json();
  if(campaign.error)return[{json:{success:false,error:campaign.error.message,step:'campaign_create'}}];
  const campaign_id=campaign.id;
  const targeting=JSON.stringify({geo_locations:{countries},age_min:18,age_max:65,publisher_platforms:['facebook','instagram']});
  const optGoal=objective==='OUTCOME_SALES'?'OFFSITE_CONVERSIONS':objective==='OUTCOME_TRAFFIC'?'LINK_CLICKS':'REACH';
  const asRes=await fetch(`${GRAPH}/act_${account}/adsets`,{
    method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},
    body:new URLSearchParams({name:`${name} - Ad Set`,campaign_id,daily_budget:String(daily_budget),billing_event:'IMPRESSIONS',optimization_goal:optGoal,targeting,status:'PAUSED',start_time,access_token:token}).toString()
  });
  const adSet=await asRes.json();
  if(adSet.error)return[{json:{success:false,error:adSet.error.message,step:'adset_create',campaign_id}}];
  result={success:true,campaign_id,adset_id:adSet.id,campaign_name:name,objective,daily_budget,countries,status:'PAUSED',message:`Campaign "${name}" created successfully (paused — review and activate when ready)`};

}else if(action==='create_audience'){
  const name=(body.name||'').trim().slice(0,120);
  if(!name)return[{json:{success:false,error:'Audience name is required'}}];
  const allowed=['CUSTOMER_FILE','WEBSITE','ENGAGEMENT'];
  const type=allowed.includes(body.type)?body.type:'CUSTOMER_FILE';
  const description=String(body.description||'').slice(0,512);
  const r=await fetch(`${GRAPH}/${account}/customaudiences`,{
    method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},
    body:new URLSearchParams({name,subtype:type,description,access_token:token}).toString()
  });
  const d=await r.json();
  result=d.error?{success:false,message:d.error.message||'Meta API error',code:d.error.code}:{success:true,id:d.id,message:'Audience created successfully'};

}else if(action==='create_lookalike'){
  if(!body.source_audience_id)return[{json:{success:false,error:'source_audience_id is required'}}];
  const ratio=Math.min(0.1,Math.max(0.01,parseFloat(body.ratio)||0.02));
  const country=String(body.country||'GB').toUpperCase().slice(0,2);
  const source_id=String(body.source_audience_id);
  const lookalike_spec=JSON.stringify({origin:[{id:source_id,type:'CUSTOM_AUDIENCE'}],ratio,country});
  const laName=`Lookalike ${country} ${Math.round(ratio*100)}%`;
  const r=await fetch(`${GRAPH}/${account}/customaudiences`,{
    method:'POST',headers:{'Content-Type':'application/json'},
    body:JSON.stringify({name:laName,subtype:'LOOKALIKE',lookalike_spec,access_token:token})
  });
  const d=await r.json();
  result=d.error?{success:false,message:d.error.message||'Meta API error',code:d.error.code}:{success:true,id:d.id,message:'Lookalike audience created — may take a few minutes to populate'};

}else{
  result={success:false,error:`Unknown action: ${action}`};
}

return[{json:result}];
